-----------------------------------------------------------------
---@class LFightIdleDrop
local LFightIdleDrop = LxClass("LFightIdleDrop",nil)
-----------------------------------------------------------------

-----------------------------------------------------------------
function LFightIdleDrop:LFightIdleDrop()
	self._index = 0
	--开始播放时间
	self._startTime = 0
	--持续时间
	self._playTime = 0

	self._trans = nil

	self._itemId = 0

	---@type LFightIdleDropCtrl
	self._ctrl = nil

	self._isDroping = false

	self._order = 0
	self._startPos = nil
	self._tarPos = nil

	self._displayObj = nil
end

-----------------------------------------------------------------

-----------------------------------------------------------------
function LFightIdleDrop:Create(idx,ctrl,itemId,order,pos,tarPos,parentTrans,dropScale)
	--itemId = "effect_drop1_1"
	self._ctrl = ctrl
	self._index = idx
	self._itemId = itemId
	self._order = order
	self._startPos = pos
	self._tarPos = tarPos
	self._dropScale = dropScale

	self._position = Vector3(0,0,0)

	self._RandZ = math.random(100, 999) * 0.0000001

	self:SetPosition(pos.x,pos.y)

	self._rootTrans = parentTrans
	self:InitDisplay()
end

function LFightIdleDrop:InitDisplay()
	local dp = LDisplaySpine:New()
	self._displayObj = dp
	dp:CreateSpine(self._rootTrans, "Jinbi")
	dp:SetScale(self._dropScale or 1)
	dp:SetUsePool(true)
	dp:SetPool(self._ctrl:GetSimplePool())
	dp:EnableReleaseFreeze(true)
	dp:SetLoadedFunction(function()
		self:OnLoaded()
	end)
end

function LFightIdleDrop:StartLoadIcon()
	self._displayObj:StartLoad()
end

function LFightIdleDrop:OnLoaded()
	if not self._displayObj or not self._displayObj:IsDpValid() then return end
	local dpTrans = self._displayObj:GetDisplayTrans()
	local collider = CS.FindTrans(dpTrans,"Collider")
	if collider and collider.gameObject.activeSelf then
		CS.ShowObject(collider,false)
	end
	--CS.ShowObject(dpTrans,false)

	self._displayObj:SetUseLookValid(true)
	self._displayObj:ClearAnimation(0)
	self._displayObj:PlayAnimation(0,self._itemId,true,false, 0)

	self:SetPosition(self._position.x, self._position.y)

	--self._displayObj:SetToSetupPose()
	--local trackEntry = self._displayObj:GetCurTrackEntry()
	--if trackEntry then
	--	trackEntry.MixTime = 0
	--	trackEntry.MixDuration = 0
	--end
	--CS.ShowObject(dpTrans,true)
end

-----------------------------------------------------------------
function LFightIdleDrop:CircleArea(circlePos)
	self._startPos = self._startPos + circlePos
	self._tarPos = self._tarPos + circlePos
	local pos = self._position + circlePos
	self:SetPosition(pos.x,pos.y)
end
-----------------------------------------------------------------

function LFightIdleDrop:StartDrop(stayTime)
	self._startTime = Time.time

	self._dropTime = math.random() * 0.2 + 0.4

	self._playTime = self._startTime + stayTime + self._dropTime

	self._isDroping = true
end

function LFightIdleDrop:RunDrop(nowTime)
	nowTime = nowTime - self._startTime

	local dropTime = self._dropTime

	local t = nowTime / dropTime

	t = Mathf.Clamp01(t)

	if t >= 1 then
		self._isDroping = false
		self._isStay = true
	end

	local fromX = self._startPos.x
	local toX = self._tarPos.x
	local fromY = self._startPos.y
	local toY = self._tarPos.y

	local topY = 1.8 + fromY

	local x = Mathf.Lerp(fromX,toX,t)
	local y = 0
	local time = t * 2
	if (time > 1) then
		--quadEaseIn
		time = time - 1
		time = time * time
		y = Mathf.Lerp(topY,toY,time)
	else
		--quadEaseOut
		time = time * (2 - time)
		y = Mathf.Lerp(fromY,topY,time)
	end
	self:SetPosition(x,y)
end

function LFightIdleDrop:SetPosition(x,y)
	local pos = self._position

	pos.x = x
	pos.y = y
	pos.z = y * 0.01 + self._RandZ

	if self._displayObj and self._displayObj:IsDpValid() then
		self._displayObj:GetDisplayTrans().position = pos
	end
end

function LFightIdleDrop:GetPosition()
	if self._displayObj and self._displayObj:IsDpValid() then
		return self._displayObj:GetDisplayTrans().position
	end
	return self._position
end

function LFightIdleDrop:IsStay()
	return self._isStay
end

function LFightIdleDrop:IsDestroy()
	return self._isDestroy
end

function LFightIdleDrop:Destroy()
	if self._isDestroy then return end
	if self._displayObj then
		--self._displayObj:ClearAnimationAll()
		self._displayObj:Destroy()
		self._displayObj = nil
	end
	table.removeall(self)
	self._isDestroy = true
end
-----------------------------------------------------------------
function LFightIdleDrop:OnRun(time)
	if self._isDestroy then return false end

	if self._isDroping  then self:RunDrop(time) end

	if self._playTime <= time then
		self:StartFlyToWnd()
		return false
	end
	return true
end

function LFightIdleDrop:StartFlyToWnd()
	local dropParam = self:GetFlyToWndParam()
	self._ctrl:AddFlyToWndList(dropParam)
end

function LFightIdleDrop:GetFlyToWndParam()
	local pos = self:GetPosition()
	return {x=pos.x, y=pos.y, itemId=self._itemId}
end

-----------------------------------------------------------------
return LFightIdleDrop


